import React, { useState } from "react";
import { Camera, CameraResultType, CameraSource } from "@capacitor/camera";

function App() {
  const [photo, setPhoto] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [recognizedName, setRecognizedName] = useState("");

  const takePhoto = async () => {
    try {
      const image = await Camera.getPhoto({
        quality: 100, // OCR 성능을 위해 고화질 설정
        allowEditing: true, // 사용자가 약 이름만 잘라낼 수 있도록 설정
        resultType: CameraResultType.Uri,
        source: CameraSource.Camera,
        saveToGallery: true,
      });
      setPhoto(image.webPath);
      setRecognizedName("");
    } catch (err) {
      console.error("카메라 오류:", err);
    }
  };

  const deletePhoto = () => {
    setPhoto(null);
    setRecognizedName("");
  };

  const startOCR = async () => {
    if (!photo) return;
    setUploading(true);

    // 기능: 토이 프로젝트용 글자 인식 시뮬레이션 (2초 후 결과 반환)
    setTimeout(() => {
      setUploading(false);
      setRecognizedName("타이레놀정 500mg"); // 가상의 인식 결과값
      alert("글자 인식을 완료했어요! 이름을 확인해 보세요.");
    }, 2000);
  };

  const useHover = () => {
    const [hover, setHover] = useState(false);
    const onMouseEnter = () => setHover(true);
    const onMouseLeave = () => setHover(false);
    return [hover, { onMouseEnter, onMouseLeave }];
  };

  const [mainBtnHover, mainBtnHoverEvents] = useHover();
  const [ocrBtnHover, ocrBtnHoverEvents] = useHover();

  return (
    <div style={wrapperStyle}>
      <header style={headerStyle}>
        <div style={headerContentStyle}>
          <h1 style={headerTitleStyle}>💊 약 이름 찾기</h1>
        </div>
      </header>

      <main style={mainStyle}>
        <div style={photoCardStyle}>
          {photo ? (
            <>
              <img src={photo} alt="Preview" style={imageStyle} />
              <button onClick={deletePhoto} style={closeButtonStyle}>
                ✕
              </button>
            </>
          ) : (
            <div style={placeholderStyle}>
              <div style={placeholderIconStyle}>📸</div>
              <p style={placeholderTextStyle}>스캔할 약봉지가 없어요</p>
              <p style={placeholderSubTextStyle}>
                아래 버튼을 눌러 사진을 찍어주세요
              </p>
            </div>
          )}
        </div>

        <div style={infoSectionStyle}>
          {uploading ? (
            <div style={loadingAreaStyle}>
              <div style={spinnerStyle}></div>
              <p
                style={{
                  ...statusStyle,
                  marginTop: 15,
                  fontWeight: "bold",
                  color: "#007bff",
                }}
              >
                열심히 글자를 읽고 있어요...
              </p>
            </div>
          ) : recognizedName ? (
            <div style={resultContainerStyle}>
              <label style={labelStyle}>
                인식된 결과 (오타가 있다면 고쳐주세요!)
              </label>
              <input
                style={inputStyle}
                value={recognizedName}
                onChange={(e) => setRecognizedName(e.target.value)} // 기능: 인식 결과 수동 수정
                placeholder="인식된 이름이 여기에 나타나요"
              />
            </div>
          ) : photo ? (
            <p style={statusStyle}>
              사진이 잘 찍혔나요? 이제 글자를 읽어볼까요?
            </p>
          ) : null}
        </div>
      </main>

      <footer style={footerStyle}>
        {!photo ? (
          <button
            onClick={takePhoto}
            style={{
              ...mainButtonStyle,
              ...(mainBtnHover ? mainButtonStyleHover : {}),
            }}
            {...mainBtnHoverEvents}
          >
            사진 찍으러 가기
          </button>
        ) : (
          <button
            onClick={startOCR}
            style={{
              ...mainButtonStyle,
              backgroundColor: recognizedName ? "#6c757d" : "#00c853",
              ...(ocrBtnHover
                ? { transform: "scale(1.02)", opacity: 0.9 }
                : {}),
            }}
            disabled={uploading}
            {...ocrBtnHoverEvents}
          >
            {uploading
              ? "읽는 중..."
              : recognizedName
              ? "다시 인식하기"
              : "글자 인식하기"}
          </button>
        )}
      </footer>
    </div>
  );
}

const wrapperStyle = {
  backgroundColor: "#f4f7f6",
  minHeight: "100vh",
  display: "flex",
  flexDirection: "column",
  fontFamily: "-apple-system, sans-serif",
};

const headerStyle = {
  paddingTop: "calc(env(safe-area-inset-top, 44px) + 10px)",
  paddingBottom: "15px",
  backgroundColor: "#fff",
  display: "flex",
  justifyContent: "center",
  borderBottom: "1px solid #e0e0e0",
};

const headerContentStyle = { display: "flex", alignItems: "center" };
const headerTitleStyle = {
  fontSize: "20px",
  margin: 0,
  fontWeight: "800",
  color: "#333",
};

const mainStyle = {
  flex: 1,
  padding: "20px",
  display: "flex",
  flexDirection: "column",
  alignItems: "center",
};

const photoCardStyle = {
  width: "100%",
  maxWidth: "360px",
  aspectRatio: "1/1",
  backgroundColor: "#fff",
  borderRadius: "28px",
  boxShadow: "0 10px 25px rgba(0,0,0,0.05)",
  position: "relative",
  overflow: "hidden",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  border: "2px dashed #ddd",
};

const imageStyle = { width: "100%", height: "100%", objectFit: "cover" };
const placeholderStyle = { textAlign: "center" };
const placeholderIconStyle = { fontSize: "50px", marginBottom: "10px" };
const placeholderTextStyle = {
  fontSize: "17px",
  fontWeight: "600",
  color: "#666",
  margin: "5px 0",
};
const placeholderSubTextStyle = { fontSize: "13px", color: "#aaa", margin: 0 };

const closeButtonStyle = {
  position: "absolute",
  top: "15px",
  right: "15px",
  width: "34px",
  height: "34px",
  borderRadius: "50%",
  backgroundColor: "rgba(0,0,0,0.4)",
  color: "#fff",
  border: "none",
  fontSize: "16px",
  zIndex: 10,
  cursor: "pointer",
};

const infoSectionStyle = {
  width: "100%",
  maxWidth: "360px",
  marginTop: "25px",
  textAlign: "center",
};
const statusStyle = {
  fontSize: "15px",
  color: "#777",
  margin: 0,
  lineHeight: "1.5",
};

const resultContainerStyle = { textAlign: "left" };
const labelStyle = {
  fontSize: "13px",
  color: "#00c853",
  fontWeight: "bold",
  marginLeft: "5px",
};
const inputStyle = {
  width: "100%",
  padding: "16px",
  marginTop: "8px",
  borderRadius: "14px",
  border: "2px solid #00c853",
  fontSize: "16px",
  fontWeight: "600",
  boxSizing: "border-box",
  outline: "none",
  backgroundColor: "#fff",
};

const loadingAreaStyle = {
  display: "flex",
  flexDirection: "column",
  alignItems: "center",
};
const spinnerStyle = {
  width: "35px",
  height: "35px",
  border: "4px solid #f3f3f3",
  borderTop: "4px solid #00c853",
  borderRadius: "50%",
  animation: "spin 1s linear infinite",
};

const footerStyle = {
  padding: "20px 20px calc(env(safe-area-inset-bottom) + 20px)",
  backgroundColor: "#fff",
  borderTop: "1px solid #eee",
};

const mainButtonStyle = {
  width: "100%",
  padding: "18px",
  borderRadius: "18px",
  border: "none",
  backgroundColor: "#007bff",
  color: "#fff",
  fontSize: "18px",
  fontWeight: "bold",
  transition: "all 0.2s",
  boxShadow: "0 5px 15px rgba(0,123,255,0.2)",
};

const mainButtonStyleHover = {
  transform: "translateY(-2px)",
  boxShadow: "0 8px 20px rgba(0,123,255,0.3)",
};

export default App;
